```cpp
// engine/platform/include/rts/platform/window.hpp
#pragma once

#include <rts/core/types.hpp>
#include <string>

struct GLFWwindow;

namespace rts {

struct WindowConfig {
    std::string title = "RTS Engine";
    u32 width = 1280;
    u32 height = 720;
    bool vsync = true;
};

class IWindow {
public:
    virtual ~IWindow() = default;

    virtual bool should_close() const = 0;
    virtual void poll_events() = 0;
    virtual void swap_buffers() = 0;
    virtual u32 width() const = 0;
    virtual u32 height() const = 0;
    virtual GLFWwindow* native_handle() const = 0;
};

class GlfwWindow : public IWindow {
public:
    explicit GlfwWindow(const WindowConfig& config);
    ~GlfwWindow() override;

    GlfwWindow(const GlfwWindow&) = delete;
    GlfwWindow& operator=(const GlfwWindow&) = delete;

    bool should_close() const override;
    void poll_events() override;
    void swap_buffers() override;
    u32 width() const override;
    u32 height() const override;
    GLFWwindow* native_handle() const override;

private:
    GLFWwindow* m_window = nullptr;
    u32 m_width = 0;
    u32 m_height = 0;
};

}  // namespace rts
```

```cpp
// engine/platform/src/window.cpp
#include <rts/platform/window.hpp>
#include <rts/core/logger.hpp>
#include <glad/glad.h>
#include <GLFW/glfw3.h>
#include <stdexcept>

namespace rts {

GlfwWindow::GlfwWindow(const WindowConfig& config)
    : m_width(config.width), m_height(config.height) {
    if (!glfwInit()) {
        throw std::runtime_error("Failed to initialize GLFW");
    }

    glfwWindowHint(GLFW_CONTEXT_VERSION_MAJOR, 3);
    glfwWindowHint(GLFW_CONTEXT_VERSION_MINOR, 3);
    glfwWindowHint(GLFW_OPENGL_PROFILE, GLFW_OPENGL_CORE_PROFILE);

    m_window = glfwCreateWindow(
        static_cast<int>(m_width),
        static_cast<int>(m_height),
        config.title.c_str(),
        nullptr, nullptr
    );

    if (!m_window) {
        glfwTerminate();
        throw std::runtime_error("Failed to create GLFW window");
    }

    glfwMakeContextCurrent(m_window);

    if (!gladLoadGLLoader(reinterpret_cast<GLADloadproc>(glfwGetProcAddress))) {
        glfwDestroyWindow(m_window);
        glfwTerminate();
        throw std::runtime_error("Failed to initialize glad");
    }

    if (config.vsync) {
        glfwSwapInterval(1);
    }

    glfwSetWindowUserPointer(m_window, this);

    glfwSetFramebufferSizeCallback(m_window, [](GLFWwindow* win, int w, int h) {
        auto* self = static_cast<GlfwWindow*>(glfwGetWindowUserPointer(win));
        self->m_width = static_cast<u32>(w);
        self->m_height = static_cast<u32>(h);
        glViewport(0, 0, w, h);
    });

    RTS_LOG_INFO("Window created: {}x{}", m_width, m_height);
}

GlfwWindow::~GlfwWindow() {
    if (m_window) {
        glfwDestroyWindow(m_window);
    }
    glfwTerminate();
}

bool GlfwWindow::should_close() const {
    return glfwWindowShouldClose(m_window);
}

void GlfwWindow::poll_events() {
    glfwPollEvents();
}

void GlfwWindow::swap_buffers() {
    glfwSwapBuffers(m_window);
}

u32 GlfwWindow::width() const { return m_width; }
u32 GlfwWindow::height() const { return m_height; }
GLFWwindow* GlfwWindow::native_handle() const { return m_window; }

}  // namespace rts
```

