```cpp
// engine/assets/src/gltf_loader.cpp
#include <rts/assets/gltf_loader.hpp>
#include <rts/core/logger.hpp>
#include <tiny_gltf.h>
#include <stdexcept>
#include <glm/gtc/type_ptr.hpp>

namespace rts {

namespace {

void process_mesh(const tinygltf::Model& gltf_model, const tinygltf::Mesh& gltf_mesh,
                  std::vector<ModelData>& out) {
    for (const auto& primitive : gltf_mesh.primitives) {
        ModelData model;

        // Positions (required)
        {
            auto it = primitive.attributes.find("POSITION");
            if (it == primitive.attributes.end()) continue;

            const auto& accessor = gltf_model.accessors[it->second];
            const auto& view = gltf_model.bufferViews[accessor.bufferView];
            const auto& buffer = gltf_model.buffers[view.buffer];
            const float* positions = reinterpret_cast<const float*>(
                buffer.data.data() + view.byteOffset + accessor.byteOffset);

            model.vertices.resize(accessor.count);
            for (size_t i = 0; i < accessor.count; ++i) {
                model.vertices[i].position = {positions[i * 3], positions[i * 3 + 1], positions[i * 3 + 2]};
            }
        }

        // Normals (optional)
        {
            auto it = primitive.attributes.find("NORMAL");
            if (it != primitive.attributes.end()) {
                const auto& accessor = gltf_model.accessors[it->second];
                const auto& view = gltf_model.bufferViews[accessor.bufferView];
                const auto& buffer = gltf_model.buffers[view.buffer];
                const float* normals = reinterpret_cast<const float*>(
                    buffer.data.data() + view.byteOffset + accessor.byteOffset);

                for (size_t i = 0; i < accessor.count; ++i) {
                    model.vertices[i].normal = {normals[i * 3], normals[i * 3 + 1], normals[i * 3 + 2]};
                }
            }
        }

        // UVs (optional)
        {
            auto it = primitive.attributes.find("TEXCOORD_0");
            if (it != primitive.attributes.end()) {
                const auto& accessor = gltf_model.accessors[it->second];
                const auto& view = gltf_model.bufferViews[accessor.bufferView];
                const auto& buffer = gltf_model.buffers[view.buffer];
                const float* uvs = reinterpret_cast<const float*>(
                    buffer.data.data() + view.byteOffset + accessor.byteOffset);

                for (size_t i = 0; i < accessor.count; ++i) {
                    model.vertices[i].uv = {uvs[i * 2], uvs[i * 2 + 1]};
                }
            }
        }

        // Bone indices (optional: JOINTS_0)
        {
            auto it = primitive.attributes.find("JOINTS_0");
            if (it != primitive.attributes.end()) {
                const auto& accessor = gltf_model.accessors[it->second];
                const auto& view = gltf_model.bufferViews[accessor.bufferView];
                const auto& buffer = gltf_model.buffers[view.buffer];

                if (accessor.componentType == TINYGLTF_COMPONENT_TYPE_UNSIGNED_SHORT) {
                    const uint16_t* joints = reinterpret_cast<const uint16_t*>(
                        buffer.data.data() + view.byteOffset + accessor.byteOffset);
                    for (size_t i = 0; i < accessor.count; ++i) {
                        for (int j = 0; j < 4; ++j) {
                            model.vertices[i].bone_ids[j] = joints[i * 4 + j];
                        }
                    }
                } else if (accessor.componentType == TINYGLTF_COMPONENT_TYPE_UNSIGNED_BYTE) {
                    const uint8_t* joints = buffer.data.data() + view.byteOffset + accessor.byteOffset;
                    for (size_t i = 0; i < accessor.count; ++i) {
                        for (int j = 0; j < 4; ++j) {
                            model.vertices[i].bone_ids[j] = joints[i * 4 + j];
                        }
                    }
                }
            }
        }

        // Bone weights (optional: WEIGHTS_0)
        {
            auto it = primitive.attributes.find("WEIGHTS_0");
            if (it != primitive.attributes.end()) {
                const auto& accessor = gltf_model.accessors[it->second];
                const auto& view = gltf_model.bufferViews[accessor.bufferView];
                const auto& buffer = gltf_model.buffers[view.buffer];
                const float* weights = reinterpret_cast<const float*>(
                    buffer.data.data() + view.byteOffset + accessor.byteOffset);

                for (size_t i = 0; i < accessor.count; ++i) {
                    for (int j = 0; j < 4; ++j) {
                        model.vertices[i].bone_weights[j] = weights[i * 4 + j];
                    }
                }
            }
        }

        // Indices
        if (primitive.indices >= 0) {
            const auto& accessor = gltf_model.accessors[primitive.indices];
            const auto& view = gltf_model.bufferViews[accessor.bufferView];
            const auto& buffer = gltf_model.buffers[view.buffer];

            model.indices.resize(accessor.count);

            if (accessor.componentType == TINYGLTF_COMPONENT_TYPE_UNSIGNED_SHORT) {
                const uint16_t* idx = reinterpret_cast<const uint16_t*>(
                    buffer.data.data() + view.byteOffset + accessor.byteOffset);
                for (size_t i = 0; i < accessor.count; ++i) {
                    model.indices[i] = idx[i];
                }
            } else if (accessor.componentType == TINYGLTF_COMPONENT_TYPE_UNSIGNED_INT) {
                const uint32_t* idx = reinterpret_cast<const uint32_t*>(
                    buffer.data.data() + view.byteOffset + accessor.byteOffset);
                for (size_t i = 0; i < accessor.count; ++i) {
                    model.indices[i] = idx[i];
                }
            }
        }

        out.push_back(std::move(model));
    }
}

void process_skeleton(const tinygltf::Model& gltf_model, const tinygltf::Skin& skin, Skeleton& skeleton) {
    skeleton.bones.resize(skin.joints.size());

    // Inverse bind matrices
    if (skin.inverseBindMatrices >= 0) {
        const auto& accessor = gltf_model.accessors[skin.inverseBindMatrices];
        const auto& view = gltf_model.bufferViews[accessor.bufferView];
        const auto& buffer = gltf_model.buffers[view.buffer];
        const float* matrices = reinterpret_cast<const float*>(
            buffer.data.data() + view.byteOffset + accessor.byteOffset);

        for (size_t i = 0; i < skin.joints.size(); ++i) {
            skeleton.bones[i].inverse_bind_pose = glm::make_mat4(matrices + i * 16);
            skeleton.bones[i].name = gltf_model.nodes[skin.joints[i]].name;
        }
    }

    // Parent indices
    for (size_t i = 0; i < skin.joints.size(); ++i) {
        int joint_node = skin.joints[i];
        const auto& node = gltf_model.nodes[joint_node];

        // Find parent in joints list
        skeleton.bones[i].parent_index = -1;
        for (size_t j = 0; j < skin.joints.size(); ++j) {
            const auto& parent_node = gltf_model.nodes[skin.joints[j]];
            for (int child : parent_node.children) {
                if (child == joint_node && j != i) {
                    skeleton.bones[i].parent_index = static_cast<i32>(j);
                }
            }
        }
    }

    // Animations
    for (const auto& anim : gltf_model.animations) {
        AnimationSequence seq;
        seq.name = anim.name;
        seq.keyframes.resize(skin.joints.size());

        for (const auto& channel : anim.channels) {
            // Find which bone index this channel targets
            int target_node = channel.target_node;
            i32 bone_idx = -1;
            for (size_t i = 0; i < skin.joints.size(); ++i) {
                if (skin.joints[i] == target_node) {
                    bone_idx = static_cast<i32>(i);
                    break;
                }
            }
            if (bone_idx < 0) continue;

            const auto& sampler = anim.samplers[channel.sampler];

            // Read timestamps
            const auto& time_accessor = gltf_model.accessors[sampler.input];
            const auto& time_view = gltf_model.bufferViews[time_accessor.bufferView];
            const auto& time_buffer = gltf_model.buffers[time_view.buffer];
            const float* times = reinterpret_cast<const float*>(
                time_buffer.data.data() + time_view.byteOffset + time_accessor.byteOffset);

            // Read values
            const auto& val_accessor = gltf_model.accessors[sampler.output];
            const auto& val_view = gltf_model.bufferViews[val_accessor.bufferView];
            const auto& val_buffer = gltf_model.buffers[val_view.buffer];
            const float* values = reinterpret_cast<const float*>(
                val_buffer.data.data() + val_view.byteOffset + val_accessor.byteOffset);

            auto& bone_kf = seq.keyframes[bone_idx];

            // Ensure enough keyframes exist
            for (size_t i = 0; i < time_accessor.count; ++i) {
                // Find or create keyframe at this time
                BoneKeyframe* kf = nullptr;
                for (auto& existing : bone_kf) {
                    if (std::abs(existing.time - times[i]) < 0.0001f) {
                        kf = &existing;
                        break;
                    }
                }
                if (!kf) {
                    bone_kf.push_back({times[i], Vec3(0.0f), Quat(1.0f, 0.0f, 0.0f, 0.0f), Vec3(1.0f)});
                    kf = &bone_kf.back();
                }

                if (channel.target_path == "translation") {
                    kf->translation = {values[i * 3], values[i * 3 + 1], values[i * 3 + 2]};
                } else if (channel.target_path == "rotation") {
                    kf->rotation = Quat(values[i * 4 + 3], values[i * 4], values[i * 4 + 1], values[i * 4 + 2]);
                } else if (channel.target_path == "scale") {
                    kf->scale = {values[i * 3], values[i * 3 + 1], values[i * 3 + 2]};
                }

                if (times[i] > seq.duration) {
                    seq.duration = times[i];
                }
            }
        }

        skeleton.animations.push_back(std::move(seq));
    }
}

}  // anonymous namespace

std::vector<ModelData> GltfLoader::load(const std::string& path) {
    tinygltf::Model gltf_model;
    tinygltf::TinyGLTF loader;
    std::string err, warn;

    bool ret;
    if (path.ends_with(".glb")) {
        ret = loader.LoadBinaryFromFile(&gltf_model, &err, &warn, path);
    } else {
        ret = loader.LoadASCIIFromFile(&gltf_model, &err, &warn, path);
    }

    if (!warn.empty()) RTS_LOG_WARN("glTF warning: {}", warn);
    if (!ret) throw std::runtime_error("Failed to load glTF: " + err);

    std::vector<ModelData> models;

    for (const auto& mesh : gltf_model.meshes) {
        process_mesh(gltf_model, mesh, models);
    }

    // Apply skeleton to all models if skins exist
    if (!gltf_model.skins.empty()) {
        Skeleton skeleton;
        process_skeleton(gltf_model, gltf_model.skins[0], skeleton);
        for (auto& model : models) {
            model.skeleton = skeleton;
        }
    }

    return models;
}

}  // namespace rts
