// engine/terrain/src/terrain.cpp
#include <rts/terrain/terrain.hpp>
#include <rts/core/logger.hpp>
#include <algorithm>
#include <cmath>

namespace rts {

TerrainData Terrain::generate(const std::vector<f32>& heights,
                               u32 grid_width, u32 grid_height, f32 cell_size) {
    TerrainData data;
    data.grid_width = grid_width;
    data.grid_height = grid_height;
    data.cell_size = cell_size;

    // Generate vertices
    data.vertices.resize(grid_width * grid_height);
    for (u32 z = 0; z < grid_height; ++z) {
        for (u32 x = 0; x < grid_width; ++x) {
            u32 idx = z * grid_width + x;
            auto& v = data.vertices[idx];
            v.position = Vec3(
                static_cast<f32>(x) * cell_size,
                heights[idx],
                static_cast<f32>(z) * cell_size
            );
            v.uv = Vec2(
                static_cast<f32>(x) / static_cast<f32>(grid_width - 1),
                static_cast<f32>(z) / static_cast<f32>(grid_height - 1)
            );
        }
    }

    // Generate indices (two triangles per quad)
    for (u32 z = 0; z < grid_height - 1; ++z) {
        for (u32 x = 0; x < grid_width - 1; ++x) {
            u32 tl = z * grid_width + x;
            u32 tr = tl + 1;
            u32 bl = (z + 1) * grid_width + x;
            u32 br = bl + 1;

            data.indices.push_back(tl);
            data.indices.push_back(bl);
            data.indices.push_back(tr);

            data.indices.push_back(tr);
            data.indices.push_back(bl);
            data.indices.push_back(br);
        }
    }

    // Calculate normals
    // Initialize to zero
    for (auto& v : data.vertices) {
        v.normal = Vec3(0.0f);
    }

    // Accumulate face normals
    for (size_t i = 0; i < data.indices.size(); i += 3) {
        auto& v0 = data.vertices[data.indices[i]];
        auto& v1 = data.vertices[data.indices[i + 1]];
        auto& v2 = data.vertices[data.indices[i + 2]];

        Vec3 edge1 = v1.position - v0.position;
        Vec3 edge2 = v2.position - v0.position;
        Vec3 face_normal = glm::cross(edge1, edge2);

        v0.normal += face_normal;
        v1.normal += face_normal;
        v2.normal += face_normal;
    }

    // Normalize
    for (auto& v : data.vertices) {
        if (glm::length(v.normal) > 0.0f) {
            v.normal = glm::normalize(v.normal);
        } else {
            v.normal = Vec3(0.0f, 1.0f, 0.0f);
        }
    }

    return data;
}

f32 Terrain::height_at(const TerrainData& data, f32 world_x, f32 world_z) {
    f32 grid_x = world_x / data.cell_size;
    f32 grid_z = world_z / data.cell_size;

    u32 x0 = static_cast<u32>(std::floor(grid_x));
    u32 z0 = static_cast<u32>(std::floor(grid_z));

    x0 = std::min(x0, data.grid_width - 1);
    z0 = std::min(z0, data.grid_height - 1);
    u32 x1 = std::min(x0 + 1, data.grid_width - 1);
    u32 z1 = std::min(z0 + 1, data.grid_height - 1);

    f32 fx = grid_x - static_cast<f32>(x0);
    f32 fz = grid_z - static_cast<f32>(z0);
    fx = std::clamp(fx, 0.0f, 1.0f);
    fz = std::clamp(fz, 0.0f, 1.0f);

    f32 h00 = data.vertices[z0 * data.grid_width + x0].position.y;
    f32 h10 = data.vertices[z0 * data.grid_width + x1].position.y;
    f32 h01 = data.vertices[z1 * data.grid_width + x0].position.y;
    f32 h11 = data.vertices[z1 * data.grid_width + x1].position.y;

    // Bilinear interpolation
    f32 h_top = h00 + (h10 - h00) * fx;
    f32 h_bottom = h01 + (h11 - h01) * fx;
    return h_top + (h_bottom - h_top) * fz;
}

std::vector<f32> Terrain::load_heightmap(const std::string& path,
                                          u32& out_width, u32& out_height) {
    // Uses stb_image to load a grayscale heightmap
    // The caller should use StbLoader for the raw load, this converts to heights
    // For now, this is a helper that loads raw pixel data as height values
    // Normalized to [0, 1] range from u8 [0, 255]
    // Full implementation deferred to editor integration
    RTS_LOG_WARN("Terrain::load_heightmap not yet integrated with StbLoader");
    out_width = 0;
    out_height = 0;
    return {};
}

}  // namespace rts
