```

```cpp
// engine/renderer/src/shader.cpp
#include <rts/renderer/shader.hpp>
#include <rts/core/logger.hpp>
#include <glad/glad.h>
#include <glm/gtc/type_ptr.hpp>
#include <fstream>
#include <sstream>
#include <stdexcept>

namespace rts {

ShaderProgram::ShaderProgram(const std::string& vertex_source, const std::string& fragment_source) {
    u32 vert = compile(vertex_source, GL_VERTEX_SHADER);
    u32 frag = compile(fragment_source, GL_FRAGMENT_SHADER);

    m_program = glCreateProgram();
    glAttachShader(m_program, vert);
    glAttachShader(m_program, frag);
    glLinkProgram(m_program);

    int success;
    glGetProgramiv(m_program, GL_LINK_STATUS, &success);
    if (!success) {
        char log[512];
        glGetProgramInfoLog(m_program, 512, nullptr, log);
        glDeleteProgram(m_program);
        glDeleteShader(vert);
        glDeleteShader(frag);
        throw std::runtime_error(std::string("Shader link error: ") + log);
    }

    glDeleteShader(vert);
    glDeleteShader(frag);
}

ShaderProgram::~ShaderProgram() {
    if (m_program) glDeleteProgram(m_program);
}

ShaderProgram::ShaderProgram(ShaderProgram&& other) noexcept : m_program(other.m_program) {
    other.m_program = 0;
}

ShaderProgram& ShaderProgram::operator=(ShaderProgram&& other) noexcept {
    if (this != &other) {
        if (m_program) glDeleteProgram(m_program);
        m_program = other.m_program;
        other.m_program = 0;
    }
    return *this;
}

void ShaderProgram::bind() const { glUseProgram(m_program); }
void ShaderProgram::unbind() const { glUseProgram(0); }

void ShaderProgram::set_int(const std::string& name, int value) const {
    glUniform1i(glGetUniformLocation(m_program, name.c_str()), value);
}

void ShaderProgram::set_float(const std::string& name, f32 value) const {
    glUniform1f(glGetUniformLocation(m_program, name.c_str()), value);
}

void ShaderProgram::set_vec3(const std::string& name, const Vec3& value) const {
    glUniform3fv(glGetUniformLocation(m_program, name.c_str()), 1, glm::value_ptr(value));
}

void ShaderProgram::set_vec4(const std::string& name, const Vec4& value) const {
    glUniform4fv(glGetUniformLocation(m_program, name.c_str()), 1, glm::value_ptr(value));
}

void ShaderProgram::set_mat4(const std::string& name, const Mat4& value) const {
    glUniformMatrix4fv(glGetUniformLocation(m_program, name.c_str()), 1, GL_FALSE, glm::value_ptr(value));
}

ShaderProgram ShaderProgram::from_files(const std::string& vertex_path, const std::string& fragment_path) {
    auto read_file = [](const std::string& path) -> std::string {
        std::ifstream file(path);
        if (!file.is_open()) {
            throw std::runtime_error("Failed to open shader file: " + path);
        }
        std::stringstream ss;
        ss << file.rdbuf();
        return ss.str();
    };

    return ShaderProgram(read_file(vertex_path), read_file(fragment_path));
}

u32 ShaderProgram::compile(const std::string& source, u32 type) {
    u32 shader = glCreateShader(type);
    const char* src = source.c_str();
    glShaderSource(shader, 1, &src, nullptr);
    glCompileShader(shader);

    int success;
    glGetShaderiv(shader, GL_COMPILE_STATUS, &success);
    if (!success) {
        char log[512];
        glGetShaderInfoLog(shader, 512, nullptr, log);
        glDeleteShader(shader);
        throw std::runtime_error(std::string("Shader compile error: ") + log);
    }

    return shader;
}

}  // namespace rts
```

