#include <gtest/gtest.h>
#include <rts/core/event_bus.hpp>

struct TestEvent {
    int value;
};

struct AnotherEvent {
    float x, y;
};

TEST(EventBusTest, SubscribeAndPublish) {
    rts::EventBus bus;
    int received = 0;

    bus.subscribe<TestEvent>([&](const TestEvent& e) {
        received = e.value;
    });

    bus.publish(TestEvent{42});
    EXPECT_EQ(received, 42);
}

TEST(EventBusTest, MultipleSubscribers) {
    rts::EventBus bus;
    int count = 0;

    bus.subscribe<TestEvent>([&](const TestEvent&) { count++; });
    bus.subscribe<TestEvent>([&](const TestEvent&) { count++; });

    bus.publish(TestEvent{1});
    EXPECT_EQ(count, 2);
}

TEST(EventBusTest, DifferentEventTypes) {
    rts::EventBus bus;
    int int_val = 0;
    float float_val = 0.0f;

    bus.subscribe<TestEvent>([&](const TestEvent& e) { int_val = e.value; });
    bus.subscribe<AnotherEvent>([&](const AnotherEvent& e) { float_val = e.x; });

    bus.publish(TestEvent{10});
    bus.publish(AnotherEvent{3.14f, 0.0f});

    EXPECT_EQ(int_val, 10);
    EXPECT_FLOAT_EQ(float_val, 3.14f);
}

TEST(EventBusTest, NoSubscribersDoesNotCrash) {
    rts::EventBus bus;
    EXPECT_NO_THROW(bus.publish(TestEvent{1}));
}

TEST(EventBusTest, UnsubscribeById) {
    rts::EventBus bus;
    int count = 0;

    auto id = bus.subscribe<TestEvent>([&](const TestEvent&) { count++; });
    bus.publish(TestEvent{1});
    EXPECT_EQ(count, 1);

    bus.unsubscribe<TestEvent>(id);
    bus.publish(TestEvent{2});
    EXPECT_EQ(count, 1);
}

