    Mat4        inverse_bind_pose   = Mat4(1.0f);
    Mat4        local_bind_transform = Mat4(1.0f);
};

struct AnimationSequence {
    std::string                        name;
    f32                                duration = 0.0f;
    bool                               looping  = true;
    // keyframes[bone_index] = vetor de keyframes do bone
    std::vector<std::vector<BoneKeyframe>> keyframes;
};

struct Skeleton {
    std::vector<Bone>              bones;
    std::vector<AnimationSequence> animations;

    bool has_bones() const { return !bones.empty(); }
};

}  // namespace rts

