    std::vector<float> heights = {
        0, 0, 0,
        0, 5, 0,
        0, 0, 0
    };
    auto data = rts::Terrain::generate(heights, 3, 3, 1.0f);
    // Vértice central (índice 4) deve ter altura 5
    EXPECT_FLOAT_EQ(data.vertices[4].position.y, 5.0f);
}

