#include <rts/assets/gltf_loader.hpp>
#include <rts/core/logger.hpp>
#include <tiny_gltf.h>
#include <glm/gtc/type_ptr.hpp>
#include <stdexcept>
#include <cmath>

namespace rts {

namespace {

void process_mesh(const tinygltf::Model& model, const tinygltf::Mesh& gltf_mesh,
                  std::vector<ModelData>& out) {
    for (const auto& primitive : gltf_mesh.primitives) {
        ModelData data;

        auto get_accessor_f32 = [&](int idx) -> const float* {
            const auto& acc  = model.accessors[idx];
            const auto& view = model.bufferViews[acc.bufferView];
            const auto& buf  = model.buffers[view.buffer];
            return reinterpret_cast<const float*>(
                buf.data.data() + view.byteOffset + acc.byteOffset);
        };

        // POSITION (required)
        {
            auto it = primitive.attributes.find("POSITION");
            if (it == primitive.attributes.end()) continue;
            const auto& acc = model.accessors[it->second];
            const float* pos = get_accessor_f32(it->second);
            data.vertices.resize(acc.count);
            for (size_t i = 0; i < acc.count; ++i) {
                data.vertices[i].position = {pos[i*3], pos[i*3+1], pos[i*3+2]};
            }
        }

        // NORMAL (optional)
        {
            auto it = primitive.attributes.find("NORMAL");
            if (it != primitive.attributes.end()) {
                const auto& acc = model.accessors[it->second];
                const float* n = get_accessor_f32(it->second);
                for (size_t i = 0; i < acc.count; ++i) {
                    data.vertices[i].normal = {n[i*3], n[i*3+1], n[i*3+2]};
                }
            }
        }

        // TEXCOORD_0 (optional)
        {
            auto it = primitive.attributes.find("TEXCOORD_0");
            if (it != primitive.attributes.end()) {
                const auto& acc = model.accessors[it->second];
                const float* uv = get_accessor_f32(it->second);
                for (size_t i = 0; i < acc.count; ++i) {
                    data.vertices[i].uv = {uv[i*2], uv[i*2+1]};
                }
            }
        }

        // JOINTS_0 (optional)
        {
            auto it = primitive.attributes.find("JOINTS_0");
            if (it != primitive.attributes.end()) {
                const auto& acc  = model.accessors[it->second];
                const auto& view = model.bufferViews[acc.bufferView];
                const auto& buf  = model.buffers[view.buffer];
                const u8* raw = buf.data.data() + view.byteOffset + acc.byteOffset;

                if (acc.componentType == TINYGLTF_COMPONENT_TYPE_UNSIGNED_SHORT) {
                    const u16* j = reinterpret_cast<const u16*>(raw);
                    for (size_t i = 0; i < acc.count; ++i) {
                        for (int k = 0; k < 4; ++k) data.vertices[i].bone_ids[k] = j[i*4+k];
                    }
                } else {
                    for (size_t i = 0; i < acc.count; ++i) {
                        for (int k = 0; k < 4; ++k) data.vertices[i].bone_ids[k] = raw[i*4+k];
                    }
                }
            }
        }

        // WEIGHTS_0 (optional)
        {
            auto it = primitive.attributes.find("WEIGHTS_0");
            if (it != primitive.attributes.end()) {
                const auto& acc = model.accessors[it->second];
                const float* w = get_accessor_f32(it->second);
                for (size_t i = 0; i < acc.count; ++i) {
                    for (int k = 0; k < 4; ++k) data.vertices[i].bone_weights[k] = w[i*4+k];
                }
            }
        }

        // Indices
        if (primitive.indices >= 0) {
            const auto& acc  = model.accessors[primitive.indices];
            const auto& view = model.bufferViews[acc.bufferView];
            const auto& buf  = model.buffers[view.buffer];
            data.indices.resize(acc.count);
            const u8* raw = buf.data.data() + view.byteOffset + acc.byteOffset;

            if (acc.componentType == TINYGLTF_COMPONENT_TYPE_UNSIGNED_SHORT) {
                const u16* idx = reinterpret_cast<const u16*>(raw);
                for (size_t i = 0; i < acc.count; ++i) data.indices[i] = idx[i];
            } else {
                const u32* idx = reinterpret_cast<const u32*>(raw);
                for (size_t i = 0; i < acc.count; ++i) data.indices[i] = idx[i];
            }
        }

        out.push_back(std::move(data));
    }
}

void process_skeleton(const tinygltf::Model& model,
                       const tinygltf::Skin& skin,
                       Skeleton& skeleton) {
    skeleton.bones.resize(skin.joints.size());

    // Inverse bind matrices
    if (skin.inverseBindMatrices >= 0) {
        const auto& acc  = model.accessors[skin.inverseBindMatrices];
        const auto& view = model.bufferViews[acc.bufferView];
        const auto& buf  = model.buffers[view.buffer];
        const float* m = reinterpret_cast<const float*>(
            buf.data.data() + view.byteOffset + acc.byteOffset);
        for (size_t i = 0; i < skin.joints.size(); ++i) {
            skeleton.bones[i].inverse_bind_pose = glm::make_mat4(m + i * 16);
            skeleton.bones[i].name = model.nodes[skin.joints[i]].name;
        }
    }

    // Parent indices
    for (size_t i = 0; i < skin.joints.size(); ++i) {
        int joint_node = skin.joints[i];
        skeleton.bones[i].parent_index = -1;
        for (size_t j = 0; j < skin.joints.size(); ++j) {
            for (int child : model.nodes[skin.joints[j]].children) {
                if (child == joint_node && j != i) {
                    skeleton.bones[i].parent_index = static_cast<i32>(j);
                }
            }
        }
    }

    // Animations
    for (const auto& anim : model.animations) {
        AnimationSequence seq;
        seq.name = anim.name;
        seq.keyframes.resize(skin.joints.size());

        for (const auto& channel : anim.channels) {
            int target_node = channel.target_node;
            i32 bone_idx = -1;
            for (size_t i = 0; i < skin.joints.size(); ++i) {
                if (skin.joints[i] == target_node) {
                    bone_idx = static_cast<i32>(i);
                    break;
                }
            }
            if (bone_idx < 0) continue;

            const auto& sampler = anim.samplers[channel.sampler];

            auto get_f32 = [&](int idx) -> const float* {
                const auto& a = model.accessors[idx];
                const auto& v = model.bufferViews[a.bufferView];
                const auto& b = model.buffers[v.buffer];
                return reinterpret_cast<const float*>(
                    b.data.data() + v.byteOffset + a.byteOffset);
            };

            const auto& time_acc = model.accessors[sampler.input];
            const float* times   = get_f32(sampler.input);
            const float* values  = get_f32(sampler.output);
            auto& bone_kf = seq.keyframes[bone_idx];

            for (size_t i = 0; i < time_acc.count; ++i) {
                BoneKeyframe* kf = nullptr;
                for (auto& existing : bone_kf) {
                    if (std::abs(existing.time - times[i]) < 0.0001f) {
                        kf = &existing;
                        break;
                    }
                }
                if (!kf) {
                    bone_kf.push_back({times[i],
                                       Vec3(0.0f),
                                       Quat(1.0f, 0.0f, 0.0f, 0.0f),
                                       Vec3(1.0f)});
                    kf = &bone_kf.back();
                }

                if (channel.target_path == "translation") {
                    kf->translation = {values[i*3], values[i*3+1], values[i*3+2]};
                } else if (channel.target_path == "rotation") {
                    kf->rotation = Quat(values[i*4+3], values[i*4], values[i*4+1], values[i*4+2]);
                } else if (channel.target_path == "scale") {
                    kf->scale = {values[i*3], values[i*3+1], values[i*3+2]};
                }

                if (times[i] > seq.duration) seq.duration = times[i];
            }
        }

        skeleton.animations.push_back(std::move(seq));
    }
}

}  // anonymous namespace

std::vector<ModelData> GltfLoader::load(const std::string& path) {
    tinygltf::Model     gltf_model;
    tinygltf::TinyGLTF  loader;
    std::string err, warn;

    bool ret;
    if (path.size() >= 4 && path.substr(path.size() - 4) == ".glb") {
        ret = loader.LoadBinaryFromFile(&gltf_model, &err, &warn, path);
    } else {
        ret = loader.LoadASCIIFromFile(&gltf_model, &err, &warn, path);
    }

    if (!warn.empty()) RTS_LOG_WARN("glTF warning: {}", warn);
    if (!ret)          throw std::runtime_error("Failed to load glTF: " + err);

    std::vector<ModelData> models;
    for (const auto& mesh : gltf_model.meshes) {
        process_mesh(gltf_model, mesh, models);
    }

    if (!gltf_model.skins.empty()) {
        Skeleton skeleton;
        process_skeleton(gltf_model, gltf_model.skins[0], skeleton);
        for (auto& m : models) m.skeleton = skeleton;
    }

    RTS_LOG_INFO("glTF loaded: {} mesh(es) from '{}'", models.size(), path);
    return models;
}

}  // namespace rts

