                        kf = &existing;
                        break;
                    }
                }
                if (!kf) {
                    bone_kf.push_back({times[i],
                                       Vec3(0.0f),
                                       Quat(1.0f, 0.0f, 0.0f, 0.0f),
                                       Vec3(1.0f)});
                    kf = &bone_kf.back();
                }

